sn_aia_tool.script:
(function execute(inputs) {

    try {

        var userQuestion = inputs.question || "";
        var userId = inputs.userid || "";

        if (!userQuestion) {
            return "Question is required.";
        }

        if (!userId) {
            return "User information is missing.";
        }

        /*
        ============================================
        BUILD INPUT PAYLOAD
        ============================================
        */

        var inputsPayload = {};

        inputsPayload["question"] = userQuestion;
        inputsPayload["userid"] = userId;

        /*
        ============================================
        ONEEXTEND EXECUTION REQUEST
        Updated with NEW Capability ID
        and NEW Skill Config ID
        ============================================
        */

        var request = {
            executionRequests: [
                {
                    payload: inputsPayload,

                    capabilityId: "47de14403bac0350ffa00e9693e45a16",

                    meta: {
                        skillConfigId: "abde14403bac0350ffa00e9693e45a9c"
                    }
                }
            ],

            mode: "sync"
        };

        /*
        ============================================
        EXECUTE SKILL
        ============================================
        */

        var response = sn_one_extend.OneExtendUtil.execute(request);

        /*
        ============================================
        IMPORTANT:
        Use SAME capabilityId here also
        Must match request capabilityId
        ============================================
        */

        var rawResponse =
            response.capabilities[
                "47de14403bac0350ffa00e9693e45a16"
            ].response;

        var finalResponse = rawResponse;

        /*
        ============================================
        HANDLE model_output RESPONSE
        Avoid wrapper responses / JSON output
        ============================================
        */

        try {

            if (typeof rawResponse == "string") {

                var parsed = JSON.parse(rawResponse);

                if (parsed.model_output) {
                    finalResponse = parsed.model_output;
                }

            } else if (
                rawResponse &&
                rawResponse.model_output
            ) {

                finalResponse = rawResponse.model_output;
            }

        } catch (e) {

            finalResponse = rawResponse;
        }

        /*
        ============================================
        FINAL CLEAN RESPONSE
        ============================================
        */

        return finalResponse;

    } catch (ex) {

        gs.error(
            "IncentNow Script Tool Error: " + ex
        );

        return "We could not process your request at the moment. Please try again later.";
    }

})(inputs);
